using System.Threading.Channels;

public class EventProcessor : IAsyncDisposable
{
    private readonly Channel<string> _channel = Channel.CreateUnbounded<string>();
    private readonly CancellationTokenSource _cts = new();
    private Task? _processingTask;

    public void Start()
    {
        _processingTask = Task.Run(() => RunLoopAsync(_cts.Token));
    }

    private async Task RunLoopAsync(CancellationToken ct)
    {
        try
        {
            // ReadAllAsync drains items as they arrive and blocks
            // asynchronously when empty — no manual signaling needed.
            await foreach (var item in _channel.Reader.ReadAllAsync(ct))
            {
                Handle(item);
            }
        }
        catch (OperationCanceledException)
        {
            // Expected on shutdown — exit gracefully.
        }
    }

    public void Enqueue(string item)
    {
        if (!_channel.Writer.TryWrite(item))
            throw new InvalidOperationException("Channel closed.");
    }

    public async ValueTask StopAsync(TimeSpan? timeout = null)
    {
        // 1. Signal no more items will be written.
        _channel.Writer.Complete();

        // 2. Give the loop time to drain remaining items.
        timeout ??= TimeSpan.FromSeconds(5);
        if (_processingTask is not null)
        {
            using var delayCts = new CancellationTokenSource(timeout.Value);
            try
            {
                await _processingTask.WaitAsync(delayCts.Token);
            }
            catch (TimeoutException)
            {
                // Drain timed out — force cancel.
                await _cts.CancelAsync();
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        await StopAsync();
        _cts.Dispose();
    }

    private void Handle(string item)
    {
        // Your processing logic here.
        Console.WriteLine($"Processed: {item}");
    }
}

